const prices = $input.all().map(i => i.json).filter(p => p.close_price);
if (prices.length < 20) return [{json: {skip: true}}];

const closes = prices.map(p => p.close_price).reverse();
const highs = prices.map(p => p.high_price).reverse();
const lows = prices.map(p => p.low_price).reverse();
const volumes = prices.map(p => p.volume).reverse();
const n = closes.length;
const current = closes[n-1];
const ticker = prices[0].ticker || '';

const sma20 = closes.slice(n-20).reduce((a,b)=>a+b,0)/20;
const std20 = Math.sqrt(closes.slice(n-20).map(c=>(c-sma20)**2).reduce((a,b)=>a+b,0)/20);
const avgVol = volumes.slice(n-20).reduce((a,b)=>a+b,0)/20;
const lastVol = volumes[n-1];
const volRatio = (lastVol / avgVol).toFixed(2);
const high5 = Math.max(...highs.slice(n-5));
const low5 = Math.min(...lows.slice(n-5));
const high20 = Math.max(...highs.slice(n-20));

const patterns = [];
const rise = closes[n-6] / closes[n-15];
const flagRange = (high5 - low5) / low5;
if (rise > 1.08 && flagRange < 0.04) {
  patterns.push({type: 'bull_flag', target: current + (closes[n-6] - closes[n-15]), confidence: 7});
}
if (current >= high20 * 0.99 && lastVol > avgVol * 1.5) {
  patterns.push({type: 'breakout', target: current * 1.05, confidence: 6});
}
if (current < sma20 - 2 * std20) {
  patterns.push({type: 'mean_reversion', target: sma20, confidence: 5});
}
const rsi_approx = 100 - 100/(1 + closes.slice(n-14).filter((c,i,a) => i>0 && c>a[i-1]).length / (closes.slice(n-14).filter((c,i,a) => i>0 && c<a[i-1]).length || 1));
if (rsi_approx < 35 && current > lows.slice(n-3).reduce((a,b)=>Math.min(a,b), Infinity)) {
  patterns.push({type: 'oversold_bounce', target: sma20, confidence: 5});
}

if (patterns.length === 0) return [{json: {skip: true}}];

return patterns.map(p => ({json: {
  ticker, company_name: prices[0].company_name || ticker,
  pattern: p.type, target_price: p.target?.toFixed(2),
  current_price: current.toFixed(2), stop_loss: (current * 0.94).toFixed(2),
  volume_ratio: volRatio, confidence: p.confidence,
  detected_at: new Date().toISOString()
}}));
